command:
// =========================
// LAIR GENERATOR
// Sandbox Generator
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

// -------------------------
// BIOME SELECTION
// -------------------------

let biome;

if (globalThis.currentHexBiome) {

    biome = globalThis.currentHexBiome;

    ui.notifications.info(
        `Using biome from Master Hex Generator: ${biome}`
    );

} else {

    biome = await Dialog.prompt({
        title: "Select Biome",
        content: `
        <p>Select the biome for the lair:</p>
        <select id="biome">
        <option>Grassland</option>
        <option>Forest</option>
        <option>Hills</option>
        <option>Marsh</option>
        <option>Mountains</option>
        </select>
        `,
        callback: html => html.find("#biome").val()
    });

}
// -------------------------
// TABLES
// -------------------------

const biomeEncounters = {
    Grassland: [
        { roll: 2, result: "Dinosaurs" },
        { roll: 3, result: "Ogres" },
        { roll: 4, result: "Gnolls" },
        { roll: 5, result: "Orcs" },
        { roll: 6, result: "Goblins" },
        { roll: 7, result: "Giant rats" },
        { roll: 8, result: "Wolves" },
        { roll: 9, result: "Bandits" },
        { roll: 10, result: "Berserkers" },
        { roll: 11, result: "Worgs" },
        { roll: 12, result: "Werewolves" }
    ],
    Forest: [
        { roll: 2, result: "Ents" },
        { roll: 3, result: "Giant spiders" },
        { roll: 4, result: "Ogres" },
        { roll: 5, result: "Bears" },
        { roll: 6, result: "Goblins" },
        { roll: 7, result: "Boars" },
        { roll: 8, result: "Wolves" },
        { roll: 9, result: "Bandits" },
        { roll: 10, result: "Elves" },
        { roll: 11, result: "Dryads" },
        { roll: 12, result: "Werewolves" }
    ],
    Hills: [
        { roll: 2, result: "Manticores" },
        { roll: 3, result: "Basilisks" },
        { roll: 4, result: "Ogres" },
        { roll: 5, result: "Orcs" },
        { roll: 6, result: "Goblins" },
        { roll: 7, result: "Giant rats" },
        { roll: 8, result: "Wolves" },
        { roll: 9, result: "Bandits" },
        { roll: 10, result: "Beastmen" },
        { roll: 11, result: "Giants" },
        { roll: 12, result: "Wyverns" }
    ],
    Marsh: [
        { roll: 2, result: "Moth-men" },
        { roll: 3, result: "Mushroom-men" },
        { roll: 4, result: "Frog-men" },
        { roll: 5, result: "Trolls" },
        { roll: 6, result: "Skeletons" },
        { roll: 7, result: "Crocodiles" },
        { roll: 8, result: "Zombies" },
        { roll: 9, result: "Orcs" },
        { roll: 10, result: "Lizard-men" },
        { roll: 11, result: "Snake-men" },
        { roll: 12, result: "Hydras" }
    ],
    Mountains: [
        { roll: 2, result: "Giants" },
        { roll: 3, result: "Griffins" },
        { roll: 4, result: "Dwarves" },
        { roll: 5, result: "Kobolds" },
        { roll: 6, result: "Orcs" },
        { roll: 7, result: "Bears" },
        { roll: 8, result: "Wolves" },
        { roll: 9, result: "Bandits" },
        { roll: 10, result: "Berserkers" },
        { roll: 11, result: "Smilodons" },
        { roll: 12, result: "Vampires" }
    ]
};

const lairTypes = [
    "Cave",
"Burrow",
"Ruined structure",
"Fortified camp",
"Hidden grove",
"Nest",
"Tunnel system",
"Sinkhole",
"Abandoned mine",
"Overgrown ruin",
"Rock shelter",
"Swamp mound"
];

const lairFeatures = [
    "Bones and refuse",
"Crude sleeping area",
"Guard post",
"Food storage",
"Prisoner cage",
"Treasure cache",
"Eggs / young",
"Ritual area",
"Weapon pile",
"Hidden escape route",
"Fresh tracks",
"Territorial markings"
];

const smallLayouts = [
    "Single chamber / central den",
"Two connected areas",
"Three small rooms branching from one entrance"
];

const largeLayouts = [
    "Linear lair with several connected rooms",
"Central chamber with side rooms",
"Looping tunnels",
"Two entrances with inner chambers",
"Split-level lair",
"Fortified camp with several zones",
"Natural cave network",
"Main den with hidden escape route"
];

const activities = [
    "Resting",
"Eating",
"Guarding treasure",
"Arguing among themselves",
"Preparing a raid",
"Recovering from a fight",
"Watching prisoners",
"Moving supplies",
"Performing a ritual",
"Sleeping"
];

// -------------------------
// MONSTER
// -------------------------

let monsterRoll1 = roll(6);
let monsterRoll2 = roll(6);
let monsterRollTotal = monsterRoll1 + monsterRoll2;
let monster = biomeEncounters[biome].find(e => e.roll === monsterRollTotal).result;

// -------------------------
// BASIC LAIR DETAILS
// -------------------------

let lairTypeRoll = roll(12);
let lairType = lairTypes[lairTypeRoll - 1];

let groupSizeRoll = roll(6);
let groupSize = groupSizeRoll <= 2 ? "Small group / solitary" : "Large group";

let layoutDie = groupSize === "Small group / solitary" ? 3 : 8;
let layoutRoll = roll(layoutDie);
let layout = groupSize === "Small group / solitary"
? smallLayouts[layoutRoll - 1]
: largeLayouts[layoutRoll - 1];

let outsidePercentRoll = roll(6);
let outsidePercent = outsidePercentRoll * 10;
let insidePercent = 100 - outsidePercent;

// -------------------------
// ENCOUNTER TYPE
// -------------------------

let inLairChance = 20;
let inLairRoll = roll(100);
let encounterType = inLairRoll <= inLairChance ? "Lair encountered" : "Patrol encountered";

let wanderingPositionRoll = roll(8);
let splitWandering = wanderingPositionRoll === 8;

let secondWanderingPositionRoll = null;
if (splitWandering) secondWanderingPositionRoll = roll(8);

// -------------------------
// ROOMS / ZONES
// -------------------------

let roomCount = groupSize === "Small group / solitary" ? layoutRoll : layoutRoll + 2;

let rooms = [];
for (let i = 1; i <= roomCount; i++) {
    let featureRoll = roll(12);
    let activityRoll = roll(10);

    rooms.push({
        number: i,
        featureRoll,
        feature: lairFeatures[featureRoll - 1],
        activityRoll,
        activity: activities[activityRoll - 1]
    });
}

// -------------------------
// TREASURE NOTE
// -------------------------

let treasureNoteRoll = roll(6);
let treasureNote = treasureNoteRoll <= 3
? "Use your system or bestiary treasure for this monster."
: "Treasure is mostly carried, hidden in the lair, or guarded by the strongest members.";

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Lair Generator</h2>

<h3>Biome and Monster</h3>
<p><b>Biome:</b> ${biome}</p>
<p><b>Biome Encounter Roll:</b> 2d6 = ${monsterRoll1} + ${monsterRoll2} = ${monsterRollTotal}</p>
<p><b>Lair Inhabitants:</b> ${monster}</p>

<hr>

<h3>Lair Type</h3>
<p><b>Lair Type Roll:</b> d12 = ${lairTypeRoll}</p>
<p><b>Lair Type:</b> ${lairType}</p>

<p><b>Group Size Roll:</b> d6 = ${groupSizeRoll}</p>
<p><b>Group Size:</b> ${groupSize}</p>

<p><b>Layout Roll:</b> d${layoutDie} = ${layoutRoll}</p>
<p><b>Layout:</b> ${layout}</p>

<hr>

<h3>Encounter Procedure</h3>
<p><b>% in Lair Used:</b> ${inLairChance}% default</p>
<p><b>In-Lair Check:</b> d100 = ${inLairRoll}</p>
<p><b>Encounter Type:</b> ${encounterType}</p>

<p><b>Outside Monster Force Roll:</b> d6 = ${outsidePercentRoll}</p>
<p><b>Outside Lair:</b> ${outsidePercent}%</p>
<p><b>Inside Lair:</b> ${insidePercent}%</p>

<p><b>Wandering Group Position Roll:</b> d8 = ${wanderingPositionRoll}</p>
<p><b>Wandering Group:</b> ${splitWandering ? "Split into two groups" : "One wandering group"}</p>
${splitWandering ? `<p><b>Second Group Position Roll:</b> d8 = ${secondWanderingPositionRoll}</p>` : ""}

<hr>

<h3>Lair Rooms / Zones</h3>
<p><b>Room Count:</b> ${roomCount}</p>
<ul>
${rooms.map(r => `
    <li>
    <b>Room/Zone ${r.number}</b><br>
    Feature Roll: d12 = ${r.featureRoll} → <b>${r.feature}</b><br>
    Activity Roll: d10 = ${r.activityRoll} → <b>${r.activity}</b>
    </li>
    `).join("")}
    </ul>

    <hr>

    <h3>Treasure</h3>
    <p><b>Treasure Note Roll:</b> d6 = ${treasureNoteRoll}</p>
    <p><b>Treasure:</b> ${treasureNote}</p>

    <hr>

    <h3>Quick Summary</h3>
    <p>
    This <b>${biome.toLowerCase()}</b> lair is home to <b>${monster.toLowerCase()}</b>.
    It is a <b>${lairType.toLowerCase()}</b> with a <b>${layout.toLowerCase()}</b>.
    About <b>${insidePercent}%</b> of the inhabitants are inside, while <b>${outsidePercent}%</b> are outside as patrols, hunters, scouts, raiders, or wanderers.
    </p>
    `;

    if (globalThis.currentHexFaction) {
        output += `
        <hr>

        <h3>Faction</h3>

        <p><b>Controlling Faction:</b></p>
        <p>${globalThis.currentHexFaction}</p>
        `;
    }

    ChatMessage.create({
        speaker: ChatMessage.getSpeaker(),
                       content: output
    });
